{
  "name": "Weatherization Assistance Program (WAP)",
  "eligibility": {
    "age": 60,
    "income_limits": "At or below 200% of the Federal Poverty Guidelines; exact dollar amounts vary by household size and are updated annually by the U.S. Department of Health and Human Services. Categorical eligibility for households receiving SSI, LIHEAP, TANF, HUD services, HOME, OLHCHH, or CDBG. Some regional programs cap at $55,000 annual household income.[1][4][5]",
    "asset_limits": "No asset limits mentioned in state guidelines.[1][4]",
    "other_requirements": ["Low-income households that rent or own their home.", "Priority given to elderly (60+), disabled, families with children, high energy burden households, high residential energy users.", "Home must typically be single-family, duplex, under 2200 sq ft, built before 2010 in some regions (e.g., PSO/Summit areas)."][1][2][3][4][5][8]
  },
  "benefits": {
    "type": "service",
    "value": "No-cost weatherization services including energy efficiency improvements such as insulation, air sealing, duct sealing, and addressing health/safety issues to reduce utility bills; includes professional energy audit and work by crews or contractors.[1][5]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local Community Action Agency (CAA) by calling Oklahoma Department of Commerce at 405-949-1495 to find your regional provider.", "Visit https://www.okcommerce.gov/weatherization/ for eligibility info and regional map.", "Apply through local CAA (e.g., NEOCAA at https://www.neocaa.org/weatherization, LIFT at https://liftca.org/weatherization); methods include in-person appointments, mail, or phone via local agency.", "No statewide online form; applications handled locally."],
    "processing_time": "Not specified statewide; varies by local provider.",
    "waitlist": "Yes, common at local agencies (e.g., NEOCAA has waiting list; applications prioritized by receipt date).[2]",
    "forms": ["Completed local application (all pages signed/dated), Verification of Employment form, signed landlord agreement for renters."],
    "documents": ["Proof of all household income (e.g., employment verification for adults 18+, Social Security award letters; no bank statements).", "Most recent electric/utility bill.", "Proof of disability if applicable.", "Deed or rental agreement signed by landlord.", "Previous 12 months utility bills (some agencies)."][2][3]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Serves all 77 Oklahoma counties via local nonprofits/CAAs partnered with Oklahoma Department of Commerce.",
    "regional_variations": "Implemented by local service contractors/CAAs in designated areas; variations in waitlists, specific docs, home size caps (e.g., PSO areas: <$65,000 income, <2200 sq ft, 10+ years old); different providers per region.",
    "offices_or_providers": ["Local Community Action Agencies (CAAs); contact via 405-949-1495 or regional map at https://www.okcommerce.gov/community-development/community-action-agencies/weatherization-assistance-program-wap/."][1][2][3][7]
  },
  "official_source": "https://www.okcommerce.gov/weatherization/",
  "gotchas": ["Must contact local CAA, not apply statewide—varies by region/provider.", "Priority tiers mean elderly may wait if not highest need; waiting lists common.", "Renters need landlord permission.", "Some areas have home size/year restrictions not in core state guidelines.", "Automatic eligibility via SSI/LIHEAP etc., but still verify with local agency.", "Funded by DOE via state; program years run April-March with potential funding limits."],
  "data_shape_notes": "Administered regionally by local CAAs serving designated areas; eligibility at 200% FPL with priority tiers; no statewide application portal, heavy reliance on local providers with varying waitlists and doc requirements."
}

{
  "name": "Legal Assistance for Seniors (Legal Aid Services of Oklahoma)",
  "eligibility": {
    "age": 60,
    "income_limits": "Generally at or below 125% of the federal poverty guidelines, calculated by household size and income. Seniors age 60 and over qualify up to 200% of the federal poverty level with qualifying income exceptions. Exact dollar amounts vary annually with federal poverty guidelines (e.g., 2024 guidelines referenced); no specific table provided in sources but based on household size. Assets considered on a case-by-case basis.",
    "asset_limits": "Determined on a case-by-case basis by each legal services program; no specific limits or exemptions detailed.",
    "other_requirements": ["Low-income civil legal issues only (non-criminal)", "Must pay all court costs and service fees", "Does not serve prisoners"]
  },
  "benefits": {
    "type": "service",
    "value": "Civil legal assistance including representation, advice, and information by attorneys and paralegals for issues like those listed on LASO's areas of law page. Provided through Older Americans Act for seniors 60+. No specific dollar amounts or hours stated.",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: https://bit.ly/46fSE13 (fill out application and click submit; check email; call to complete if needed)", "Phone: 1-888-534-5243 or 918-428-4357 (Mon-Thu 9am-4pm; do not leave voicemail)", "Seniors-specific helpline: Oklahoma Sixty-Plus Legal Aid Services Helpline (OK-SPLASH) at 1-855-488-6814", "In-person: LASO offices (e.g., Hugo Law Office, Oklahoma City Law Office)"],
    "processing_time": "Not specified; intake specialist decides after gathering income, household size, and legal issue details.",
    "waitlist": null,
    "forms": ["Online application form at https://bit.ly/46fSE13"],
    "documents": ["Proof of income, household size, and details of legal issue (prepare to provide during intake)"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Serves all of Oklahoma through 18 offices; some offices cover specific counties (e.g., Hugo Law Office, Oklahoma City covers Canadian and Oklahoma Counties)",
    "regional_variations": "Income guidelines may vary slightly by office (e.g., 125% at OKC office, up to 200% at Hugo); different local offices handle intake",
    "offices_or_providers": ["18 offices statewide, e.g., Hugo Law Office (fax 580-326-9658), Oklahoma City Law Office, Administration at 3800 N. Classen Blvd, Suite 230, Oklahoma City, OK 73118"]
  },
  "official_source": "https://legalaidok.org/apply/",
  "gotchas": ["Calls only answered Mon-Thu 9am-4pm; no voicemails", "Must pay court costs and service fees even if eligible", "Assets reviewed case-by-case beyond income", "Limited capacity; not all qualifying cases accepted due to LSC restrictions and high demand", "Civil matters only; no criminal cases or prisoners"],
  "data_shape_notes": "Seniors 60+ get higher income threshold (up to 200%); statewide with 18 regional offices and slight guideline variations; funded by LSC and Older Americans Act; case acceptance not guaranteed even if eligible"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to all residents regardless of financial status.",
    "asset_limits": "No asset limits; no financial tests apply.",
    "other_requirements": ["Must be a resident of a licensed long-term care facility in Oklahoma, including nursing homes, assisted living, or residential care homes. Complaints can be made by residents, friends, or family on their behalf with resident consent for investigation."][1][2][7]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Receives and investigates complaints about care, rights, or facility issues; communicates with facility staff to resolve problems; provides information on residents' rights, laws, and regulations; explores issues and recommends corrective actions with resident consent; conducts facility visits and assessments; advocates for quality of life and care improvements.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Toll-free 1-800-211-2116 (Senior InfoLine) or local (405) 521-6734[3][7]", "Contact local Area Agency on Aging Ombudsman supervisor (11 agencies statewide)[7][8]", "Email via Oklahoma.gov/oag contact form[2]"],
    "processing_time": "Not specified; ombudsmen respond to complaints as received, typically involving prompt communication and investigation.",
    "waitlist": null,
    "forms": ["No specific application forms; process involves submitting a complaint verbally or in writing."],
    "documents": ["No documents required to initiate; resident consent needed for full investigation. Provide details of complaint, facility name, and resident information."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to licensed long-term care facilities (nursing homes, assisted living, residential care); facilities must be licensed by Oklahoma Department of Health[2][5].",
    "regional_variations": "Administered through 11 Area Agencies on Aging with local supervisors and volunteers; contact varies by region (e.g., INCOG for Tulsa area[5], ASCOG for specific southwest counties with supervisors Dacia Nix (580-736-7975) and Darin Terry (580-736-7974)[8]).",
    "offices_or_providers": ["11 Area Agencies on Aging; statewide coordination via OKCares, OKDHS Aging Services, and Office of Attorney General[1][2][7]"]
  },
  "official_source": "https://oklahoma.gov/oag/about/divisions/ltco.html",
  "gotchas": ["Not a direct service provider (e.g., no healthcare, funding, or placement services); focuses solely on advocacy and complaint resolution[1][2][4].", "Requires resident consent for investigation and recommendations[1][2].", "Does not handle unlicensed facilities or non-facility home care (though some states expand; Oklahoma focuses on facilities)[6].", "Complaints about care quality can also go directly to Oklahoma Department of Health; ombudsman complements this[2].", "Volunteer-based in regions, so availability may depend on local staffing[2][8]."],
  "data_shape_notes": "no income test; facility-residency only; decentralized via 11 regional Area Agencies on Aging; advocacy/complaint-focused, not benefits-paying"
}

{
  "name": "Oklahoma Chore Services (Older Americans Act Title III)",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits or verification required. Services prioritize those with greatest economic or social need, low-income minorities, rural residents, severe disabilities, or at risk for institutional placement, but open to all[1][2].",
    "asset_limits": "No asset limits or verification required[2].",
    "other_requirements": ["Difficulty with one or more Instrumental Activities of Daily Living (IADLs)[1]", "Must own and live in the home where services are needed[1]", "Assessed by Area Agency on Aging (AAA) for needs[1][2]"]
  },
  "benefits": {
    "type": "service",
    "value": "Heavy housework, yard work, or sidewalk maintenance. Up to $150 per year for materials and disposable supplies to complete tasks[1].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local Area Agency on Aging (AAA) by phone or in-person for assessment. Statewide Aging Services: oklahoma.gov/okdhs/services/cap/older-americans-act.html[1]", "ASCOG AAA example: www.ascog.org/supportive-services/ or contact provider directly to confirm eligibility[3]"],
    "processing_time": "Initial needs assessment by AAA; annual review if needs change. No specific statewide timeline stated[1].",
    "waitlist": "Not mentioned; may vary by AAA and region[1][3].",
    "forms": ["Necessary forms completed at initial evaluation, including service information and client details[1]"],
    "documents": ["Income information may be requested voluntarily for other program referrals, but not required for eligibility[1][2]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered through 11 Area Agencies on Aging (AAAs) covering specific Planning Service Areas (PSAs)[2][3].",
    "regional_variations": "Delivered by local AAA-contracted providers; services, wait times, and availability differ by AAA and region (e.g., ASCOG in its PSA)[1][2][3].",
    "offices_or_providers": ["Network of 11 AAAs; contact local AAA via oklahoma.gov/okdhs/services/cap/older-americans-act.html[1][2][3]"]
  },
  "official_source": "https://oklahoma.gov/okdhs/services/cap/older-americans-act.html",
  "gotchas": ["Not limited to low-income, but priority given to greatest need; may ask for income info only for other programs[1][2]", "Must have IADL difficulty and live in own home[1]", "Services free but donations accepted; annual reassessment required[1][2]", "Apply through local AAA, not centralized state office[1][3]"],
  "data_shape_notes": "Administered regionally by 11 AAAs with needs-based assessment and priority tiers; no income/asset test; $150 annual materials cap"
}
